\text{Para despejar la } x \text{, debemos multiplicar (o dividir) ambos lados por } -1.\text{¡Ojo! Al multiplicar por un número negativo, la dirección de la desigualdad se invierte:}
\begin{aligned}
(-1)(-x) & > (-1)(4) \\
x & > -4
\end{aligned}\text{Solución: } (-4, \infty)

\text{Primero factorizamos el trinomio buscando dos números que multiplicados den } -8 \text{ y sumados } -2:
\begin{aligned}
x^2 - 2x - 8 & \geq 0 \\
(x - 4)(x + 2) & \geq 0
\end{aligned}
\text{Puntos críticos: } x = 4, \; x = -2 \text{ (Cerrados por el símbolo } \geq \text{)}
\text{Al hacer el análisis de signos en la recta real, los intervalos exteriores nos dan un producto positivo:}
\text{Para } x < -2 \text{ y para } x > 4, \text{ el resultado es positivo } (\geq 0).\text{Solución: } (-\infty, -2] \cup [4, \infty)

\text{Podemos resolverlo desarrollando el binomio o usando raíces. Usaremos el desarrollo:}
\begin{aligned}
x^2 - 6x + 9 & \geq 4 \\
x^2 - 6x + 9 - 4 & \geq 0 \\
x^2 - 6x + 5 & \geq 0
\end{aligned}\text{Factorizamos buscando números que multiplicados den } 5 \text{ y sumados } -6:(x - 5)(x - 1) \geq 0\text{Puntos críticos: } x = 5, \; x = 1 \text{ (Cerrados por el } \geq \text{)}\text{Al pedirnos } \geq 0 \text{ (positivo), tomamos los intervalos exteriores de la parábola.}\text{Solución: } (-\infty, 1] \cup [5, \infty)

\text{Para que una fracción sea positiva (} > 0 \text{), el numerador y el denominador deben tener el mismo signo.}
\text{Como el numerador es } 1 \text{ (positivo), obligatoriamente el denominador debe ser positivo:}
\begin{aligned}
x - 2 & > 0 \\
x & > 2
\end{aligned}\text{El } 2 \text{ no se incluye porque haría que el denominador fuera cero. Solución: } (2, \infty)

\text{Primero, factorizamos tanto el numerador como el denominador:}\begin{aligned}
\frac{(x + 3)(x - 2)}{(x - 2)(x + 2)} & \geq 0
\end{aligned}\text{Podemos simplificar el término } (x - 2) \text{, pero debemos recordar la restricción vital: el denominador original no puede ser cero, por lo que } x \neq 2.\text{La inecuación simplificada queda: } \frac{x + 3}{x + 2} \geq 0 \quad \text{con } x \neq 2.\text{Puntos críticos: } x = -3 \text{ (cerrado por el } \geq \text{) y } x = -2 \text{ (abierto por estar en el denominador).}
\text{Evaluando signos, la expresión es positiva en } (-\infty, -3] \text{ y en } (-2, \infty).\text{Sin embargo, debemos excluir el } 2 \text{ del intervalo derecho.}\text{Solución: } (-\infty, -3] \cup (-2, 2) \cup (2, \infty)

\text{Paso 1: Calculamos el dominio de la raíz:}\begin{aligned}
2x + 1 & \geq 0 \\
2x & \geq -1 \\
x & \geq -\frac{1}{2}
\end{aligned}\text{Paso 2: Elevamos al cuadrado a ambos lados y despejamos:}\begin{aligned}
(\sqrt{2x + 1})^2 & \leq 5^2 \\
2x + 1 & \leq 25 \\
2x & \leq 24 \\
x & \leq 12
\end{aligned}\text{Paso 3: Intersecamos los dos resultados. La } x \text{ arranca obligatoriamente desde } -\frac{1}{2} \text{ (incluido) y llega como máximo hasta el } 12 \text{ (incluido).}-\frac{1}{2} \leq x \leq 12\text{Solución: } \left[-\frac{1}{2}, 12\right]

\text{Paso 1: Calculamos el dominio. El radicando debe ser } \geq 0\text{:}x^2 - 5x + 6 \geq 0 \implies (x - 3)(x - 2) \geq 0\text{Esto se cumple en: } (-\infty, 2] \cup [3, \infty)\text{Paso 2: Condición del lado derecho. Como una raíz siempre es } \geq 0\text{, para que sea estrictamente menor a } (x - 1)\text{, este lado derecho debe ser positivo:}x - 1 > 0 \implies x > 1\text{Intersecando esta condición con el dominio del Paso 1, nos queda el "universo válido": } (1, 2] \cup [3, \infty)\text{Paso 3: Elevamos ambos lados al cuadrado:}\begin{aligned}
x^2 - 5x + 6 & < (x - 1)^2 \\
x^2 - 5x + 6 & < x^2 - 2x + 1 \\
-3x & < -5 \\
x & > \frac{5}{3}
\end{aligned}\text{Paso 4: Intersecamos este resultado } \left( x > \frac{5}{3} \right) \text{ con nuestro universo válido } ((1, 2] \cup [3, \infty)).\text{Solución: } \left(\frac{5}{3}, 2\right] \cup [3, \infty)

